mapper.select:
select vid, docid, content, editor, createtime, created_at, created_by, snapshot_type, labels, is_locked, diff_stats, file_size, parent_vid from doc_version where docid = #{docid}
and (editor like concat('%', #{search}, '%') or JSON_SEARCH(labels, 'one', concat('%', #{search}, '%')) is not null)
order by createtime desc limit #{limit} offset #{offset}

select vid, docid, content, editor, createtime, created_at, created_by, snapshot_type, labels, is_locked, diff_stats, file_size, parent_vid from doc_version where docid = #{docid}
and (editor like concat('%', #{search}, '%') or JSON_SEARCH(labels, 'one', concat('%', #{search}, '%')) is not null)
order by createtime desc limit #{limit} offset #{offset}

select vid from doc_version
where docid = #{docid}
and is_locked = false
and snapshot_type != 'auto_milestone'
order by createtime asc
limit #{limit}

select vid from doc_version
where docid = #{docid}
and is_locked = false
and snapshot_type != 'auto_milestone'
order by createtime asc
limit #{limit}

mapper.delete:
delete from doc_version where docid in (
    select docid from doc where docroomid = #{roomid}
)

mapper.update:
update doc_version 
set content = #{content, jdbcType=BLOB}, createtime = #{updatedAt}
where vid = #{vid}
